/**
 * Webhook notification handler for order events.
 *
 * Subscribes to order events via EventBus and dispatches HTTP webhook
 * callbacks to registered URLs. Follows the same EventBus subscription
 * pattern as NotificationService and EmailNotificationHandler.
 *
 * Depends on:
 * - EventBus (event system) for receiving order lifecycle events
 */

import type { EventBus } from '../events/event-bus.js';
import type { EventType, OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventType: EventType;
  secret?: string;
  registeredAt: Date;
}

export interface WebhookDelivery {
  id: string;
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: WebhookPayload;
  success: boolean;
  statusCode: number;
  deliveredAt: Date;
}

export interface WebhookPayload {
  event: EventType;
  timestamp: string;
  data: Record<string, unknown>;
}

export type HttpPoster = (url: string, payload: WebhookPayload, secret?: string) => Promise<{ success: boolean; statusCode: number }>;

const defaultHttpPoster: HttpPoster = async () => ({
  success: true,
  statusCode: 200,
});

let nextRegistrationId = 1;
let nextDeliveryId = 1;

function generateRegistrationId(): string {
  return `webhook-${String(nextRegistrationId++).padStart(4, '0')}`;
}

function generateDeliveryId(): string {
  return `delivery-${String(nextDeliveryId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounters(): void {
  nextRegistrationId = 1;
  nextDeliveryId = 1;
}

export class WebhookHandler {
  private logger = new Logger('WebhookHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];
  private httpPost: HttpPoster;

  constructor(
    private eventBus: EventBus,
    httpPost: HttpPoster = defaultHttpPoster,
  ) {
    this.httpPost = httpPost;
    this.registerHandlers();
  }

  /**
   * Register EventBus handlers for order events that trigger webhooks.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Register a webhook URL for a specific event type.
   */
  registerWebhook(url: string, eventType: EventType, secret?: string): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: generateRegistrationId(),
      url,
      eventType,
      secret,
      registeredAt: new Date(),
    };
    this.registrations.push(registration);
    this.logger.info(`Webhook registered: ${registration.id} for ${eventType} -> ${url}`);
    return registration;
  }

  /**
   * Unregister a webhook by ID.
   */
  unregisterWebhook(id: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === id);
    if (index >= 0) {
      this.registrations.splice(index, 1);
      this.logger.info(`Webhook unregistered: ${id}`);
      return true;
    }
    return false;
  }

  /**
   * Get all registered webhooks.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get registrations for a specific event type.
   */
  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
    return this.registrations.filter((r) => r.eventType === eventType);
  }

  /**
   * Get all delivery records.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get deliveries for a specific webhook.
   */
  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  /**
   * Get the count of deliveries.
   */
  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  /**
   * Clear all registrations and deliveries (useful for testing).
   */
  clearAll(): void {
    this.registrations = [];
    this.deliveries = [];
  }

  /**
   * Dispatch webhook to all registered URLs for a given event type.
   */
  private async dispatchWebhooks(eventType: EventType, payload: WebhookPayload): Promise<void> {
    const targets = this.registrations.filter((r) => r.eventType === eventType);

    for (const target of targets) {
      try {
        const result = await this.httpPost(target.url, payload, target.secret);
        const delivery: WebhookDelivery = {
          id: generateDeliveryId(),
          webhookId: target.id,
          url: target.url,
          eventType,
          payload,
          success: result.success,
          statusCode: result.statusCode,
          deliveredAt: new Date(),
        };
        this.deliveries.push(delivery);
        this.logger.info(
          `Webhook delivered: ${delivery.id} to ${target.url} (${result.statusCode})`,
        );
      } catch (error) {
        const delivery: WebhookDelivery = {
          id: generateDeliveryId(),
          webhookId: target.id,
          url: target.url,
          eventType,
          payload,
          success: false,
          statusCode: 0,
          deliveredAt: new Date(),
        };
        this.deliveries.push(delivery);
        this.logger.info(`Webhook delivery failed: ${delivery.id} to ${target.url}`);
      }
    }
  }

  /**
   * Handle order created event — dispatch to registered webhooks.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const payload: WebhookPayload = {
      event: 'order:created',
      timestamp: event.timestamp.toISOString(),
      data: {
        orderId: event.order.id,
        userId: event.order.userId,
        items: event.order.items,
        total: event.order.total,
        status: event.order.status,
      },
    };
    await this.dispatchWebhooks('order:created', payload);
  }

  /**
   * Handle order status changed event — dispatch to registered webhooks.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    const payload: WebhookPayload = {
      event: 'order:status-changed',
      timestamp: event.timestamp.toISOString(),
      data: {
        orderId: event.order.id,
        userId: event.order.userId,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    };
    await this.dispatchWebhooks('order:status-changed', payload);
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  WebhookHandler,
  resetWebhookIdCounters,
  type HttpPoster,
  type WebhookPayload,
} from '../../src/notifications/webhook-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('WebhookHandler', () => {
  let eventBus: EventBus;
  let webhookHandler: WebhookHandler;
  let mockHttpPost: ReturnType<typeof vi.fn<HttpPoster>>;

  beforeEach(() => {
    resetWebhookIdCounters();
    eventBus = new EventBus();
    mockHttpPost = vi.fn<HttpPoster>().mockResolvedValue({ success: true, statusCode: 200 });
    webhookHandler = new WebhookHandler(eventBus, mockHttpPost);
  });

  const makeCreatedEvent = (): OrderCreatedEvent => ({
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date('2026-01-15T10:00:00Z'),
  });

  const makeStatusEvent = (
    previousStatus: string,
    newStatus: string,
  ): OrderStatusChangedEvent => ({
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: newStatus as 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus,
    newStatus,
    timestamp: new Date('2026-01-15T10:00:00Z'),
  });

  describe('webhook registration', () => {
    it('should register a webhook and return registration', () => {
      const reg = webhookHandler.registerWebhook(
        'https://example.com/hook',
        'order:created',
      );

      expect(reg.id).toBe('webhook-0001');
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventType).toBe('order:created');
      expect(reg.registeredAt).toBeInstanceOf(Date);
    });

    it('should register a webhook with a secret', () => {
      const reg = webhookHandler.registerWebhook(
        'https://example.com/hook',
        'order:created',
        'my-secret',
      );

      expect(reg.secret).toBe('my-secret');
    });

    it('should assign unique IDs to registrations', () => {
      const reg1 = webhookHandler.registerWebhook('https://a.com', 'order:created');
      const reg2 = webhookHandler.registerWebhook('https://b.com', 'order:created');

      expect(reg1.id).not.toBe(reg2.id);
    });

    it('should list all registrations', () => {
      webhookHandler.registerWebhook('https://a.com', 'order:created');
      webhookHandler.registerWebhook('https://b.com', 'order:status-changed');

      expect(webhookHandler.getRegistrations()).toHaveLength(2);
    });

    it('should filter registrations by event type', () => {
      webhookHandler.registerWebhook('https://a.com', 'order:created');
      webhookHandler.registerWebhook('https://b.com', 'order:status-changed');
      webhookHandler.registerWebhook('https://c.com', 'order:created');

      expect(webhookHandler.getRegistrationsForEvent('order:created')).toHaveLength(2);
      expect(webhookHandler.getRegistrationsForEvent('order:status-changed')).toHaveLength(1);
    });

    it('should unregister a webhook by ID', () => {
      const reg = webhookHandler.registerWebhook('https://a.com', 'order:created');

      expect(webhookHandler.unregisterWebhook(reg.id)).toBe(true);
      expect(webhookHandler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering non-existent webhook', () => {
      expect(webhookHandler.unregisterWebhook('webhook-9999')).toBe(false);
    });
  });

  describe('order:created webhook delivery', () => {
    it('should deliver webhook on order created', async () => {
      webhookHandler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeCreatedEvent());

      expect(mockHttpPost).toHaveBeenCalledTimes(1);
      const [url, payload] = mockHttpPost.mock.calls[0]!;
      expect(url).toBe('https://example.com/hook');
      expect(payload.event).toBe('order:created');
      expect(payload.data.orderId).toBe('order-1');
      expect(payload.data.userId).toBe('user-1');
      expect(payload.data.total).toBe(20);
    });

    it('should include items in order:created payload', async () => {
      webhookHandler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeCreatedEvent());

      const payload = mockHttpPost.mock.calls[0]![1] as WebhookPayload;
      const items = payload.data.items as Array<{ name: string }>;
      expect(items).toHaveLength(1);
      expect(items[0]?.name).toBe('Widget');
    });

    it('should include ISO timestamp in payload', async () => {
      webhookHandler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeCreatedEvent());

      const payload = mockHttpPost.mock.calls[0]![1] as WebhookPayload;
      expect(payload.timestamp).toBe('2026-01-15T10:00:00.000Z');
    });

    it('should pass secret to http poster', async () => {
      webhookHandler.registerWebhook('https://example.com/hook', 'order:created', 'secret-123');

      await eventBus.emit(makeCreatedEvent());

      expect(mockHttpPost).toHaveBeenCalledWith(
        'https://example.com/hook',
        expect.any(Object),
        'secret-123',
      );
    });

    it('should not deliver to webhooks registered for other events', async () => {
      webhookHandler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeCreatedEvent());

      expect(mockHttpPost).not.toHaveBeenCalled();
    });

    it('should deliver to multiple registered webhooks', async () => {
      webhookHandler.registerWebhook('https://a.com/hook', 'order:created');
      webhookHandler.registerWebhook('https://b.com/hook', 'order:created');

      await eventBus.emit(makeCreatedEvent());

      expect(mockHttpPost).toHaveBeenCalledTimes(2);
    });
  });

  describe('order:status-changed webhook delivery', () => {
    it('should deliver webhook on status change', async () => {
      webhookHandler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      expect(mockHttpPost).toHaveBeenCalledTimes(1);
      const payload = mockHttpPost.mock.calls[0]![1] as WebhookPayload;
      expect(payload.event).toBe('order:status-changed');
      expect(payload.data.previousStatus).toBe('pending');
      expect(payload.data.newStatus).toBe('confirmed');
      expect(payload.data.orderId).toBe('order-1');
    });

    it('should not deliver to webhooks registered for order:created', async () => {
      webhookHandler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      expect(mockHttpPost).not.toHaveBeenCalled();
    });
  });

  describe('delivery tracking', () => {
    it('should record successful delivery', async () => {
      webhookHandler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeCreatedEvent());

      const deliveries = webhookHandler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(true);
      expect(deliveries[0]?.statusCode).toBe(200);
      expect(deliveries[0]?.url).toBe('https://example.com/hook');
    });

    it('should record failed delivery on HTTP error', async () => {
      mockHttpPost.mockResolvedValueOnce({ success: false, statusCode: 500 });
      webhookHandler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeCreatedEvent());

      const deliveries = webhookHandler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(false);
      expect(deliveries[0]?.statusCode).toBe(500);
    });

    it('should record failed delivery on network error', async () => {
      mockHttpPost.mockRejectedValueOnce(new Error('Network error'));
      webhookHandler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeCreatedEvent());

      const deliveries = webhookHandler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(false);
      expect(deliveries[0]?.statusCode).toBe(0);
    });

    it('should filter deliveries by webhook ID', async () => {
      const reg1 = webhookHandler.registerWebhook('https://a.com', 'order:created');
      webhookHandler.registerWebhook('https://b.com', 'order:created');

      await eventBus.emit(makeCreatedEvent());

      expect(webhookHandler.getDeliveriesForWebhook(reg1.id)).toHaveLength(1);
      expect(webhookHandler.getDeliveryCount()).toBe(2);
    });

    it('should clear all registrations and deliveries', async () => {
      webhookHandler.registerWebhook('https://example.com/hook', 'order:created');
      await eventBus.emit(makeCreatedEvent());

      webhookHandler.clearAll();

      expect(webhookHandler.getRegistrations()).toHaveLength(0);
      expect(webhookHandler.getDeliveries()).toHaveLength(0);
    });
  });

  describe('integration with EventBus', () => {
    it('should work alongside other handlers on the same EventBus', async () => {
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );
      resetNotificationIdCounter();
      const notifService = new NotificationService(eventBus);
      webhookHandler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      expect(notifService.getNotificationCount()).toBe(1);
      expect(webhookHandler.getDeliveryCount()).toBe(1);
    });

    it('should log events in EventBus event log', async () => {
      webhookHandler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeCreatedEvent());

      const log = eventBus.getEventLog();
      expect(log).toHaveLength(1);
      expect(log[0]?.type).toBe('order:created');
    });

    it('should not fire after unregistering webhook', async () => {
      const reg = webhookHandler.registerWebhook('https://example.com/hook', 'order:created');
      webhookHandler.unregisterWebhook(reg.id);

      await eventBus.emit(makeCreatedEvent());

      expect(mockHttpPost).not.toHaveBeenCalled();
      expect(webhookHandler.getDeliveryCount()).toBe(0);
    });

    it('should use default http poster when none provided', async () => {
      const defaultHandler = new WebhookHandler(eventBus);
      defaultHandler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeCreatedEvent());

      // Default poster returns success — just verify delivery was recorded
      expect(defaultHandler.getDeliveryCount()).toBe(1);
      expect(defaultHandler.getDeliveries()[0]?.success).toBe(true);
    });
  });
});

